import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Kbd.module.css';

export type KbdRootProps = HTMLArkProps<'kbd'>;
export type KbdGroupProps = HTMLArkProps<'kbd'>;

const KbdRoot = forwardRef<HTMLElement, KbdRootProps>(function KbdRoot(
  { className, ...props },
  ref,
) {
  return (
    <ark.kbd
      ref={ref}
      data-scope="kbd"
      data-part="root"
      data-slot="kbd-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const KbdGroupPart = forwardRef<HTMLElement, KbdGroupProps>(function KbdGroupPart(
  { className, ...props },
  ref,
) {
  return (
    <ark.kbd
      ref={ref}
      data-scope="kbd"
      data-part="group"
      data-slot="kbd-group"
      className={clsx(styles.group, normalizeClassName(className))}
      {...props}
    />
  );
});

const Kbd = Object.assign(KbdRoot, {
  Root: KbdRoot,
  Group: KbdGroupPart,
});

export { Kbd };

@layer ui.components {
  .root[data-scope='kbd'][data-part='root'] {
    box-sizing: border-box;
    display: inline-flex;
    flex: none;
    min-width: var(--kbd-min-width, var(--kbd-height, 1.5rem));
    max-width: 100%;
    height: var(--kbd-height, 1.5rem);
    align-items: center;
    justify-content: center;
    overflow: hidden;
    border: var(--kbd-border-width, var(--border-width-sm)) solid
      var(--kbd-border-color, var(--color-border));
    border-radius: var(--kbd-radius, var(--radius-sm));
    padding: var(--kbd-padding-y, 0) var(--kbd-padding-x, 0.4375rem);
    background-color: var(--kbd-bg, var(--color-muted));
    box-shadow: var(
      --kbd-shadow,
      inset 0 -1px 0 color-mix(in oklab, var(--color-foreground) 12%, transparent)
    );
    color: var(--kbd-color, var(--color-foreground));
    font-family: var(--kbd-font-family, var(--font-mono)), monospace;
    font-size: var(--kbd-font-size, var(--text-xs));
    font-weight: var(--kbd-font-weight, var(--weight-medium));
    line-height: var(--kbd-line-height, var(--line-height-text-xs));
    font-variant-numeric: tabular-nums;
    text-align: center;
    vertical-align: middle;
    white-space: nowrap;
    user-select: none;
  }

  .group[data-scope='kbd'][data-part='group'] {
    box-sizing: border-box;
    display: inline-flex;
    max-width: 100%;
    align-items: center;
    gap: var(--kbd-group-gap, 0.25rem);
    padding: 0;
    border: 0;
    background: none;
    box-shadow: none;
    color: var(--kbd-group-separator-color, var(--color-muted-foreground));
    font: inherit;
    vertical-align: middle;
    white-space: nowrap;
  }
}
